/**
 * Sets the coordinates of this 2D grid point.
 *
 * @param x X coordinate
 * @param y Y coordinate
 *
 * @return this 2D grid point for chaining.
 */
public GridPoint2Mutant set(int x, int y) {
    this.x = x;
    this.y = y;
    return this;
}
